"""Тесты обработчика секции extract (ExtractConfig в sections)."""from src.modules.file_extract import get_default_extract_payloadfrom src.modules.file_extract.providers import PdfExtractProviderfrom src.modules.project.sections import ExtractConfigdef test_get_default_returns_dict_from_schema() -> None:    """Умолчание генерируется по схеме провайдеров (есть pdf_extract_provider)."""    default = ExtractConfig.get_default()    assert isinstance(default, dict)    assert default == get_default_extract_payload()    assert "pdf_extract_provider" in default    assert isinstance(default["pdf_extract_provider"], dict)def test_validate_valid_payload_returns_empty_list() -> None:    """Валидный payload по схеме не даёт ошибок."""    payload = get_default_extract_payload()    assert ExtractConfig.validate(payload) == []def test_validate_empty_dict_returns_list() -> None:    """validate({}) возвращает список (схема может требовать поля в группах)."""    errors = ExtractConfig.validate({})    assert isinstance(errors, list)def test_validate_non_dict_returns_error() -> None:    """Не-словарь даёт ошибку."""    errors = ExtractConfig.validate(None)    assert len(errors) == 1    assert "объект" in errors[0] or "dict" in errors[0]    assert ExtractConfig.validate([]) != []    assert ExtractConfig.validate("extract") != []def test_validate_unknown_group_code_returns_error() -> None:    """Неизвестный код группы даёт ошибку валидации."""    errors = ExtractConfig.validate({"unknown_group": {"key": "value"}})    assert len(errors) >= 1    assert "Extract:" in errors[0]    assert "unknown" in errors[0].lower() or "group" in errors[0].lower()def test_validate_invalid_field_value_returns_error() -> None:    """Недопустимое значение поля в группе даёт ошибку."""    payload = {        "pdf_extract_provider": {            "enabled": True,            "mode": PdfExtractProvider.PDF_EXTRACT_MODE_ONLY_TEXT,            "min_text_length": -1,        },    }    errors = ExtractConfig.validate(payload)    assert len(errors) >= 1    assert "Extract:" in errors[0]